import{_ as i,o as t,c as s,a2 as a}from"./chunks/framework.Cuq8tsM6.js";const c=JSON.parse('{"title":"3. Validation & Diffusion","description":"","frontmatter":{"title":"3. Validation & Diffusion"},"headers":[],"relativePath":"docs/fr/advertisers/dedicated-email/3-validation-diffusion.md","filePath":"docs/fr/advertisers/dedicated-email/3-validation-diffusion.md"}'),o={name:"docs/fr/advertisers/dedicated-email/3-validation-diffusion.md"};function n(r,e,d,l,u,p){return t(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="etape-3-validation-et-diffusion" tabindex="-1">Étape 3 : Validation et Diffusion <a class="header-anchor" href="#etape-3-validation-et-diffusion" aria-label="Permalink to &quot;Étape 3 : Validation et Diffusion&quot;">​</a></h1><p>La création est terminée. Il ne reste plus qu&#39;à valider le BAT (Bon à Tirer) pour autoriser l&#39;envoi.</p><hr><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Configuration du Tracking</h3><p>Cette étape est transparente pour vous. L&#39;équipe getinside et le distributeur intègrent les pixels d&#39;ouverture et les liens de redirection trackés.</p><p><strong>Rappel :</strong> vos liens sont dynamiques — vous pouvez modifier l&#39;URL de destination à tout moment dans l&#39;onglet <strong>&quot;Configuration et Suivi&quot;</strong>, même après validation.</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Réception du BAT</h3><p>Dès que le distributeur a finalisé l&#39;email et que getinside l&#39;a vérifié techniquement, vous recevez une notification par email.</p><p>Vous accédez à une <strong>prévisualisation statique</strong> de la campagne pour vérifier le respect du brief (offre, visuels, wording).</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Votre Validation (Action Requise)</h3><p>Si la création vous convient, vous devez valider sur la plateforme pour débloquer l&#39;envoi.</p></div></div><div class="warning custom-block"><p class="custom-block-title">Action requise pour débloquer l&#39;envoi</p><ol><li>Connectez-vous sur <a href="https://app.getinside.media/" target="_blank">app.getinside.media</a>.</li><li>Ouvrez la campagne concernée.</li><li>Cliquez sur le bouton <strong>&quot;Valider la campagne&quot;</strong>.</li></ol><p>Tant que vous ne validez pas, la campagne reste bloquée — elle ne sera pas diffusée.</p></div><div class="gi-step"><div class="gi-step-num done">4</div><div class="gi-step-body"><h3>Diffusion</h3><p>Une fois les deux validations enregistrées (la vôtre + celle du distributeur), la campagne est programmée et envoyée à l&#39;audience ciblée.</p><p>Suivez les statistiques (ouvertures, clics) en temps réel depuis votre tableau de bord.</p></div></div><div class="tip custom-block"><p class="custom-block-title">Renvoi aux non-ouvreurs</p><p>Certains distributeurs proposent un renvoi automatique de la campagne aux abonnés qui n&#39;ont pas ouvert l&#39;email lors du premier envoi. Demandez-le lors du brief pour maximiser la couverture.</p></div>',9)])])}const f=i(o,[["render",n]]);export{c as __pageData,f as default};
